import{_ as e,a as o}from"./chunks/firmware 3.B7OrWKPL.js";import{_ as a}from"./chunks/reference ardusub frame.DQ4XMWrt.js";import{_ as i}from"./chunks/quick start autodetect motors.Bts2IrGD.js";import{_ as r}from"./chunks/reference ardusub power psmr2.DmFgOsdG.js";import{_ as n}from"./chunks/reference ardusub camera.BQm4cCoL.js";import{_ as l}from"./chunks/reference ardusub lights.pCKNEgQC.js";import{_ as s,o as u,c as h,ag as c}from"./chunks/framework.DXGyWiRo.js";const d="/assets/reference%20operational%20joystick%20defaults.HB5_bBQr.",g="/assets/quick%20start%20sensor%20calibration%20complete.B3cSR35X.",p="/assets/quick%20start%20manual%20motor%20directions.reiS_p8e.",m="/assets/quick%20start%20leak%20sensor.EgawhpSj.",f="/assets/failsafe.BIlqPC9L.",F=JSON.parse('{"title":"Installing Autopilot Firmware","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/installing-autopilot-firmware.md","filePath":"robotics/installing-autopilot-firmware.md"}'),b={name:"robotics/installing-autopilot-firmware.md"};function q(w,t,k,y,S,C){return u(),h("div",null,[...t[0]||(t[0]=[c('<h1 id="installing-autopilot-firmware" tabindex="-1">Installing Autopilot Firmware <a class="header-anchor" href="#installing-autopilot-firmware" aria-label="Permalink to &quot;Installing Autopilot Firmware&quot;">​</a></h1><h2 id="installing-ardusub" tabindex="-1">Installing ArduSub <a href="#installing-ardusub" id="installing-ardusub"></a> <a class="header-anchor" href="#installing-ardusub" aria-label="Permalink to &quot;Installing ArduSub &lt;a href=&quot;#installing-ardusub&quot; id=&quot;installing-ardusub&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><blockquote><p>The current Stable version of ArduSub is <strong>v4.0.3</strong>. If your firmware is out of date, it may be updated by following one of the methods below.</p></blockquote><p>ArduSub is the firmware binary which resides on the flash memory of the autopilot board.</p><p>It may be installed (or updated) in one of two ways:</p><ol><li>Connecting it to a Companion Computer and pressing the appropriate button.</li><li>Directly connecting the board to a Topside Computer with QGroundControl via a USB cable.</li></ol><h3 id="with-a-companion-computer-automatic-installation" tabindex="-1">With a Companion Computer (Automatic Installation) <a href="#with-a-companion-computer-automatic-installation" id="with-a-companion-computer-automatic-installation"></a> <a class="header-anchor" href="#with-a-companion-computer-automatic-installation" aria-label="Permalink to &quot;With a Companion Computer (Automatic Installation) &lt;a href=&quot;#with-a-companion-computer-automatic-installation&quot; id=&quot;with-a-companion-computer-automatic-installation&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>To load ArduSub onto an autopilot board:</p><ol><li>Plug a <em>fully charged</em> battery into the vehicle and connect the tether to the topside computer.</li><li>Navigate to <a href="http://192.168.2.2:2770/network" target="_blank" rel="noreferrer">192.168.2.2:2770/network</a> in an internet browser (Chrome, Edge, Firefox, etc.) and ensure that the vehicle has access to a WiFi network. If you do not see a webpage at this address, verify the network settings are correct. Troubleshooting steps can be found here.</li><li>Navigate to <a href="http://192.168.2.2:2770/system" target="_blank" rel="noreferrer">192.168.2.2:2770/system</a>. Click the button under the <em>Pixhawk Firmware Update</em> section that says <strong>Stable</strong>.</li><li>Wait for the update process to complete, and you are finished!</li></ol><h3 id="without-a-companion-computer-manual-installation" tabindex="-1">Without a Companion Computer (Manual Installation) <a href="#without-a-companion-computer-manual-installation" id="without-a-companion-computer-manual-installation"></a> <a class="header-anchor" href="#without-a-companion-computer-manual-installation" aria-label="Permalink to &quot;Without a Companion Computer (Manual Installation) &lt;a href=&quot;#without-a-companion-computer-manual-installation&quot; id=&quot;without-a-companion-computer-manual-installation&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>Open QGroundControl and navigate <strong>Firmware</strong> page.</li><li>Plug in the Pixhawk to the computer&#39;s USB port. Once detected, QGroundControl will show a firmware selection box on the right.</li><li>Choose <strong>&quot;ArduPilot Flight Stack&quot;</strong>, then select <strong>&quot;ChibiOS&quot;</strong>, <strong>&quot;Sub&quot;</strong>, and (assuming you are using a Pixhawk) <strong>&quot;Pixhawk1&quot;</strong> from the dropdown list.</li></ol><p><img src="'+e+'" alt=""></p><ol><li>Press &quot;OK&quot; at the top right.</li><li>The firmware will upload the Pixhawk and you&#39;ll see the following printout and success message. The Pixhawk will reboot and then will automatically connect with QGroundControl.</li></ol><p><img src="'+o+'" alt=""></p><h3 id="frame-selection" tabindex="-1">Frame Selection <a href="#frame-selection" id="frame-selection"></a> <a class="header-anchor" href="#frame-selection" aria-label="Permalink to &quot;Frame Selection &lt;a href=&quot;#frame-selection&quot; id=&quot;frame-selection&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>Go the <strong>Frame Setup</strong> page.</li><li>Click on the corresponding vehicle frame that was originally picked out in the &quot;Building a Vehicle Frame&quot; section of this documentation.</li><li>Reboot the vehicle or autopilot for the frame selection to be saved and loaded on the next start.</li></ol><p><img src="'+a+'" alt=""></p><blockquote><p>Default parameters only exist for the BlueROV2 and BlueROV2 Heavy. If using another frame type, parameter settings will need to be manually configured in the following steps.</p></blockquote><h3 id="completing-calibrations" tabindex="-1">Completing Calibrations <a href="#completing-calibrations" id="completing-calibrations"></a> <a class="header-anchor" href="#completing-calibrations" aria-label="Permalink to &quot;Completing Calibrations &lt;a href=&quot;#completing-calibrations&quot; id=&quot;completing-calibrations&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Before an ArduSub vehicle may be used, several calibration and setup steps must be completed for it to function correctly.</p><h3 id="joystick-gamepad-calibration" tabindex="-1">Joystick/Gamepad Calibration <a href="#joystickgamepad-calibration" id="joystickgamepad-calibration"></a> <a class="header-anchor" href="#joystick-gamepad-calibration" aria-label="Permalink to &quot;Joystick/Gamepad Calibration &lt;a href=&quot;#joystickgamepad-calibration&quot; id=&quot;joystickgamepad-calibration&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Some joysticks require calibration before they can be enabled for use with QGroundControl. If a joystick requires calibration, the <a href="https://github.com/bluerobotics/ardusub-gitbook/blob/ArduSub-Docs-Overhaul/reference/ardusub/joystick-setup-page.md" target="_blank" rel="noreferrer"><strong>Joystick</strong></a> tab will be red, and these steps should be followed to calibrate the joystick. If the joystick does not require calibration, the <strong>Joystick</strong> tab will not be red, and this step can be skipped!</p><ol><li>Go to the <strong>Joystick</strong> page in the sidebar on the left.</li><li>Ensure the &#39;TX Mode&#39; selection is set to 3.</li><li>Click on the &quot;Calibration&quot; tab, then click &quot;Next&quot;.</li><li>Follow the step-by-step instructions, move the sticks as indicated in the diagram in QGroundControl.</li></ol><p>When completed, the <strong>Joystick</strong> tab will no longer be red, and the <em>Enabled</em> checkbox on the Joystick page should be checked.</p><h3 id="button-setup" tabindex="-1">Button Setup <a href="#button-setup" id="button-setup"></a> <a class="header-anchor" href="#button-setup" aria-label="Permalink to &quot;Button Setup &lt;a href=&quot;#button-setup&quot; id=&quot;button-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The default button setup for ArduSub is as shown in the image below:</p><p><img src="'+d+'" alt=""></p><p>The button functions may be reconfigured in the <strong>Joystick</strong> page.</p><h3 id="sensor-calibration" tabindex="-1">Sensor Calibration <a href="#sensor-calibration" id="sensor-calibration"></a> <a class="header-anchor" href="#sensor-calibration" aria-label="Permalink to &quot;Sensor Calibration &lt;a href=&quot;#sensor-calibration&quot; id=&quot;sensor-calibration&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>Go to the <strong>Sensors</strong> tab in the sidebar on the left.</li><li>Click on the <strong>Accelerometers</strong> tab and follow the instructions.</li><li>Choose <strong>Roll90</strong> for the <strong>Autopilot Orientation</strong> selection.</li><li>Click on <strong>Compass</strong> and follow the instructions.</li><li>Click on <strong>Calibrate Pressure</strong> and wait for the calibration to complete.</li></ol><p>When completed, the <strong>Sensors</strong> tab will no longer be red.</p><p><img src="'+g+'" alt=""></p><h3 id="configure-motor-directions" tabindex="-1">Configure Motor Directions <a href="#configure-motor-directions" id="configure-motor-directions"></a> <a class="header-anchor" href="#configure-motor-directions" aria-label="Permalink to &quot;Configure Motor Directions &lt;a href=&quot;#configure-motor-directions&quot; id=&quot;configure-motor-directions&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><strong>The direction that the motors will spin depends on how the vehicle and motors were assembled, so each motor&#39;s forward/reverse direction must be configured in software.</strong></p><p>To begin, navigate to the <strong>Motors</strong> tab in the sidebar on the left, then proceed with the <strong>automatic</strong> (recommended) or <strong>manual</strong> configuration.</p><blockquote><p>Be sure to keep all body parts and clothing clear of thrusters while the vehicle is armed.</p><p><strong>Warning</strong> <strong>DO NOT</strong> run thrusters for longer than 30 seconds in air or you will wear out the plastic bearings.</p></blockquote><h4 id="automatic-configuration" tabindex="-1">Automatic Configuration <a href="#automatic-configuration" id="automatic-configuration"></a> <a class="header-anchor" href="#automatic-configuration" aria-label="Permalink to &quot;Automatic Configuration &lt;a href=&quot;#automatic-configuration&quot; id=&quot;automatic-configuration&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ol><li>Adjust the vehicle&#39;s buoyancy to be neutral or slightly <strong>positive</strong>.</li><li>Place the vehicle in water with enough room for it to move around slightly without bumping into walls or the bottom. Make sure the vehicle has a bit of slack in the tether so that it can move freely.</li><li>Go to the <strong>Motors</strong> tab in the sidebar on the left.</li><li>Click the <strong>Auto-Detect Directions</strong> button, and wait while the vehicle does it&#39;s motor direction detection routine.</li><li>The results of the routine will appear as the routine progresses, and success or failure will be indicated. If the routine failed, you may try again, or configure the motor directions <strong>manually</strong>.</li></ol><p><img src="'+i+'" alt=""></p><h4 id="manual-configuration" tabindex="-1">Manual Configuration <a href="#manual-configuration" id="manual-configuration"></a> <a class="header-anchor" href="#manual-configuration" aria-label="Permalink to &quot;Manual Configuration &lt;a href=&quot;#manual-configuration&quot; id=&quot;manual-configuration&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ol><li>Go to the <strong>Motors</strong> tab in the sidebar on the left.</li><li>Read and understand the instructions on the setup page.</li><li>Arm the vehicle by clicking the switch on the page.</li><li>One at a time, move each slider, and make sure that the motor that spins is pushing air as described in the instructions on the Motor Setup page. If a motor is spinning in the wrong direction, click the corresponding checkbox under the &#39;Reverse Motor Direction&#39; section to correct the motor rotation.</li><li>When you are finished with the setup, disarm the vehicle by clicking the switch.</li></ol><p><img src="'+p+'" alt=""></p><h3 id="voltage-and-current-measurement-setup" tabindex="-1">Voltage and Current Measurement Setup <a href="#voltage-and-current-measurement-setup" id="voltage-and-current-measurement-setup"></a> <a class="header-anchor" href="#voltage-and-current-measurement-setup" aria-label="Permalink to &quot;Voltage and Current Measurement Setup &lt;a href=&quot;#voltage-and-current-measurement-setup&quot; id=&quot;voltage-and-current-measurement-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>In the <strong>Power</strong> tab , select <strong>Analog Voltage and Current</strong> and enter the values according to the manufacturers specifications.</p><p>If using a <a href="https://bluerobotics.com/store/comm-control-power/elec-packages/psm-asm-r2-rp/" target="_blank" rel="noreferrer">Blue Robotics Power Sense Module</a>, select the “Blue Robotics Power Sense Module R2” profile for the Power Sensor.</p><p><img src="'+r+'" alt=""></p><h3 id="sos-leak-sensor-setup" tabindex="-1">SOS Leak Sensor Setup <a href="#sos-leak-sensor-setup" id="sos-leak-sensor-setup"></a> <a class="header-anchor" href="#sos-leak-sensor-setup" aria-label="Permalink to &quot;SOS Leak Sensor Setup &lt;a href=&quot;#sos-leak-sensor-setup&quot; id=&quot;sos-leak-sensor-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>In the <strong>Safety</strong> tab, select the output channel that the leak detector in is plugged into, and set the Logic when dry to &quot;Low.&quot;</p><p><img src="'+m+'" alt=""></p><h3 id="setup-low-voltage-failsafe" tabindex="-1">Setup Low Voltage Failsafe <a href="#setup-low-voltage-failsafe" id="setup-low-voltage-failsafe"></a> <a class="header-anchor" href="#setup-low-voltage-failsafe" aria-label="Permalink to &quot;Setup Low Voltage Failsafe &lt;a href=&quot;#setup-low-voltage-failsafe&quot; id=&quot;setup-low-voltage-failsafe&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>On the <strong>Safety</strong> tab set the battery failsafe to Warning and the desired voltage or capacity to trigger the alarm. Remember you will need some power to go back home.</p><p><img src="'+f+'" alt=""></p><blockquote><p>Lithium Batteries should not be overdischarged, as it damages their internal chemistry. Do not let each cell&#39;s voltage get lower than 3.0 V.</p></blockquote><h3 id="camera-tilt-setup-if-used" tabindex="-1">Camera Tilt Setup (if used) <a href="#camera-tilt-setup-if-used" id="camera-tilt-setup-if-used"></a> <a class="header-anchor" href="#camera-tilt-setup-if-used" aria-label="Permalink to &quot;Camera Tilt Setup (if used) &lt;a href=&quot;#camera-tilt-setup-if-used&quot; id=&quot;camera-tilt-setup-if-used&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>Select the <strong>Camera</strong> tab.</li><li>The &quot;Gimbal Tilt&quot; settings are used for the camera tilt.</li><li>Choose whichever channel the servo is plugged into for &quot;Output channel&quot;. Valid output channels are any of the unused MAIN motor outputs (1-8), and AUX outputs 1-4 (9-12).</li><li>Select <em>Servo</em> for the &quot;Type&quot; under &quot;Gimbal Settings&quot; at the bottom.</li></ol><p><img src="'+n+'" alt=""></p><p>If desired, you can check the <em>Stabilize</em> box, which will enable auto-stabilization of the camera based on the vehicle pitch angle. We generally leave this unchecked.</p><h3 id="lights-setup" tabindex="-1">Lights Setup <a href="#lights-setup" id="lights-setup"></a> <a class="header-anchor" href="#lights-setup" aria-label="Permalink to &quot;Lights Setup &lt;a href=&quot;#lights-setup&quot; id=&quot;lights-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>The output channel for the lights is configured in the <strong>Lights</strong> tab.</li><li>Select the output channel that you have plugged your lights into, as shown below.</li></ol><blockquote><p>This setup only works with lights that are controllable with a servo PWM pulse, such as the Blue Robotics <a href="https://bluerobotics.com/store/thrusters/lights/lumen-r2-rp/" target="_blank" rel="noreferrer"><em>Lumen</em> Lights</a>.</p></blockquote><p><img src="'+l+'" alt=""></p><h3 id="sd-card-formatting" tabindex="-1">SD Card Formatting <a href="#sd-card-formatting" id="sd-card-formatting"></a> <a class="header-anchor" href="#sd-card-formatting" aria-label="Permalink to &quot;SD Card Formatting &lt;a href=&quot;#sd-card-formatting&quot; id=&quot;sd-card-formatting&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The SD card inside of the autopilot (eg Pixhawk) is where ArduSub stores its dataflash logs. It should be formatted as a FAT/exFAT/FAT32 partition. If it gets corrupted or has a different filesystem, you should format it.</p><p>The following steps will help you format it:</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',67)])])}const B=s(b,[["render",q]]);export{F as __pageData,B as default};
